import json
def scan(f):
    with open(f) as fh:
        for line in fh:
            try: d=json.loads(line)
            except: continue
            rt=d.get('record_type')
            if rt not in ('assistant_message','message','response'):
                # print types seen
                pass
            s=json.dumps(d)
            for kw in ['counterexample','star','infinite family','axiom','cannot suffice','pure set']:
                if kw in s.lower():
                    print(f, rt, 'kw=',kw)
                    break
seen=set()
for f in ['scratch/logs-round1.jsonl','scratch/logs-round2.jsonl']:
    with open(f) as fh:
        for line in fh:
            try: d=json.loads(line)
            except: continue
            seen.add(d.get('record_type'))
print("record types:", seen)
EOF
